#include<bits/stdc++.h>
using namespace std;
int a[1010];
int dp[1010][40010];
const int mod=998244353;
int main()
{
    int n;
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&a[i]);
    }
    int ans=n;
    for(int i=1;i<=n;i++)
    {
        for(int j=i-1;j>=1;j--)
        {
            int tmp=a[i]-a[j]+20000;
            dp[i][tmp]+=dp[j][tmp]+1;
            dp[i][tmp]%=mod;
            ans+=dp[j][tmp]+1;
            ans%=mod;
        }
    }
    printf("%d",ans);
    return 0;
}
